import asyncio
import json
from playwright.async_api import async_playwright, Page
import anthropic

client = anthropic.Anthropic()

TOOLS = [
    {
        'name': 'click_element',
        'description': 'Click an element by visible text or CSS selector.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'selector': {'type': 'string', 'description': 'CSS selector'},
                'by_text': {'type': 'string', 'description': 'Visible text of the element'},
            },
        },
    },
    {
        'name': 'fill_input',
        'description': 'Fill a form input with the given value.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'label': {'type': 'string', 'description': 'Accessible label of the input'},
                'value': {'type': 'string', 'description': 'Text to enter'},
            },
            'required': ['label', 'value'],
        },
    },
]

async def observe_page(page: Page) -> str:
    snapshot = await page.accessibility.snapshot()
    return json.dumps(snapshot, indent=2)[:4000]

async def execute_tool(page: Page, name: str, inputs: dict) -> str:
    if name == 'click_element':
        if inputs.get('by_text'):
            await page.get_by_text(inputs['by_text']).first.click()
        else:
            await page.locator(inputs['selector']).click()
        return 'clicked'
    elif name == 'fill_input':
        await page.get_by_label(inputs['label']).fill(inputs['value'])
        return 'filled'
    return 'unknown tool'

async def run_agent(task: str, url: str):
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page()
        await page.goto(url)
        messages = [{'role': 'user', 'content': f'Task: {task}\n\nPage:\n{await observe_page(page)}'}]
        for _ in range(20):
            response = client.messages.create(
                model='claude-opus-4-5',
                max_tokens=1024,
                tools=TOOLS,
                messages=messages,
            )
            if response.stop_reason == 'end_turn':
                print('Done:', response.content[0].text)
                break
            tool_uses = [b for b in response.content if b.type == 'tool_use']
            if not tool_uses:
                break
            messages.append({'role': 'assistant', 'content': response.content})
            results = []
            for tu in tool_uses:
                result = await execute_tool(page, tu.name, tu.input)
                await page.wait_for_load_state('networkidle', timeout=3000)
                results.append({
                    'type': 'tool_result',
                    'tool_use_id': tu.id,
                    'content': result + '\n\nNew state:\n' + await observe_page(page),
                })
            messages.append({'role': 'user', 'content': results})
        await browser.close()

asyncio.run(run_agent('Find and click the Sign Up button', 'https://example.com'))
